import React, { useState } from 'react'; 
import axios from 'axios'; 
const Search = () => { 
  const [kw, setKw] = useState(''); 
  const [res, setRes] = useState([]); 
  const handleS = async () => { 
    const {data} = await axios.get(`http://localhost:5000/api/songs/search?q=${kw}`); 
    setRes(data); 
  }; 
  return ( 
    <div style={{padding:'20px'}}> 
      <input onChange={e=>setKw(e.target.value)} placeholder="Tim..." /> 
      <button onClick={handleS}>Tim</button> 
      {res.map(s=><div key={s._id}>{s.title}</div>)} 
    </div> 
  ); 
}; export default Search;
